package com.google.gson;

import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertDoesNotThrow;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

class GsonCheckValidFloatingPointTest {

  @Test
  void testCheckValidFloatingPoint_withValidValues() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    // Valid finite double values should not throw
    assertDoesNotThrow(() -> method.invoke(null, 0.0));
    assertDoesNotThrow(() -> method.invoke(null, -123.456));
    assertDoesNotThrow(() -> method.invoke(null, Double.MIN_VALUE));
    assertDoesNotThrow(() -> method.invoke(null, Double.MAX_VALUE));
    assertDoesNotThrow(() -> method.invoke(null, 1.0e10));
  }

  @Test
  void testCheckValidFloatingPoint_withNaN_throws() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    assertThrows(IllegalArgumentException.class,
        () -> method.invoke(null, Double.NaN));
  }

  @Test
  void testCheckValidFloatingPoint_withPositiveInfinity_throws() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    assertThrows(IllegalArgumentException.class,
        () -> method.invoke(null, Double.POSITIVE_INFINITY));
  }

  @Test
  void testCheckValidFloatingPoint_withNegativeInfinity_throws() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    assertThrows(IllegalArgumentException.class,
        () -> method.invoke(null, Double.NEGATIVE_INFINITY));
  }
}
